parameters.jsCode:
const run = $json;
const services = [
  'ChatGPT', 'Claude', 'Gemini', 'Cursor', 'Midjourney', 'ElevenLabs',
  'Perplexity', 'Runway', 'HeyGen', 'Mistral', 'Replit', 'n8n'
];
const sources = [
  { service: 'ChatGPT', source: 'official_pricing', url: 'https://chatgpt.com/pricing' },
  { service: 'Claude', source: 'official_pricing', url: 'https://www.anthropic.com/pricing' },
  { service: 'Gemini', source: 'official_pricing', url: 'https://one.google.com/about/ai-premium/' },
  { service: 'AppSumo', source: 'deal_marketplace', url: 'https://appsumo.com/search/?q=AI' },
  { service: 'StackSocial', source: 'deal_marketplace', url: 'https://www.stacksocial.com/search?query=ai' },
  { service: 'Reddit ChatGPT', source: 'community_json', url: 'https://www.reddit.com/r/ChatGPT.json' }
];
return sources.map((item) => ({
  json: {
    run_id: run.id,
    mode: run.mode,
    services,
    current_date: new Date().toISOString(),
    ...item,
  }
}));

const body = $json.body;
const raw = typeof body === 'string' ? body : JSON.stringify(body ?? {});
const clean = raw
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const content = clean.slice(0, 12000);
const normalizedUrl = ($json.url || '').replace(/\?.*$/, '');
const contentHash = require('crypto').createHash('sha256').update(`${$json.service}|${$json.source}|${normalizedUrl}|${content.slice(0, 4000)}`).digest('hex');
return [{ json: {
  run_id: $json.run_id,
  mode: $json.mode,
  current_date: $json.current_date,
  service: $json.service,
  source: $json.source,
  source_url: $json.url,
  normalized_url: normalizedUrl,
  raw_text: content,
  content_hash: contentHash,
  title: `${$json.service} / ${$json.source}`,
  price_before: '',
  price_now: '',
  discount_text: '',
  deal_type: 'unknown',
  score_hint: 0,
}}];

const items = $input.all().map((x) => x.json);
const first = items[0] || {};
return [{ json: {
  run_id: first.run_id,
  mode: first.mode,
  current_date: first.current_date,
  raw_items_json: JSON.stringify(items),
}}];

const aggregated = $('Aggregate Items').first().json;
const previous = $json;
return [{ json: {
  run_id: aggregated.run_id,
  mode: aggregated.mode,
  current_date: aggregated.current_date,
  prev_report: previous.prev_report || '',
  active_deals_json: JSON.stringify(previous.active_deals || []),
  raw_items_json: aggregated.raw_items_json,
}}];

